const fs = require\('fs'\);
// Basic syntax check via JSON parse for manifest
const manifest = JSON.parse\(fs.readFileSync\('manifest.json', 'utf8'\)\);
console.log\('manifest.json: OK'\);
console.log\('  permissions:', manifest.permissions\);
console.log\('  host_permissions:', manifest.host_permissions\);
console.log\('  content_scripts:', manifest.content_scripts?.[0]?.matches\);

// Check all JS files can be parsed
['background.js', 'popup.js', 'options.js', 'content.js'].forEach\(f => {
  try {
    new Function\(fs.readFileSync\(f, 'utf8'\)\);
    console.log\(f + ': syntax OK \(' + fs.readFileSync\(f, 'utf8'\).split\('\\n'\).length + ' lines\)'\);
  } catch\(e\) {
    console.error\(f + ': SYNTAX ERROR - ' + e.message\);
  }
}\);
")
